void main(void)
{
    vec3 normal = normalize(gl_NormalMatrix * gl_Normal);	// カメラ座標に変換。
    gl_TexCoord[0].st = (normal.xy + vec2(1.0, 1.0)) / 2.0;		// -1～1を0～1に変換。
    gl_Position = ftransform();
}

